mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM travel_plans
    WHERE id = #{id}
      AND writer_email = #{writerEmail}
)

mapper.update:
UPDATE travel_plans
SET title = #{title},
    duration_days = #{durationDays}
WHERE id = #{id}
  AND writer_email = #{writerEmail}

mapper.delete:
DELETE FROM travel_plans
WHERE id = #{id}
  AND writer_email = #{writerEmail}

mapper.update:
UPDATE travel_plans
SET is_shared = #{shared}
WHERE id = #{id}
  AND writer_email = #{writerEmail}
